import aside from '@/components/shared/aside/aside';
import nav from '@/components/shared/nav/nav';
import { ComponentModule, render } from '@/main';
import { Presale } from '@/models/presunto';
import { Vendedor } from '@/models/vendedor';
import { url } from '@/services/api.service';
import { getAuthenticatedCompany, getAuthenticatedUser } from '@/services/auth.service';

export default {
    name: () => 'presaleList',
    template: () => import('./presale-list.html?raw'),
    data: () => ({
        user: getAuthenticatedUser(),
        empresa: getAuthenticatedCompany(),
        nav: null as string | null,
        aside: null as string | null,
        loading: true,
        presales: null as Presale[] | null,
        vendedores: null as Vendedor[] | null,

        currentTab: 0,

        vendedorName(ven: number): string {
            const vendedor = this.vendedores?.find((v: Vendedor) => v.ven === ven);
            return vendedor?.raz || '';
        },

        async init() {
            console.log('presaleList@init');

            this.nav = await render(nav);
            this.aside = await render(aside);

            this.loading = false;

            await Promise.all([this.loadPresales(), this.loadVendedores()]);
        },

        async loadPresales() {
            this.loading = true;
            let fetchUrl = '';
            switch (this.currentTab) {
                case 0:
                    fetchUrl = 'isiWeb/web/v1/empresas/01/presuntos?conf:ne=false';
                    break;
                case 1:
                    fetchUrl = 'isiWeb/web/v1/empresas/01/presuntos?conf:ne=false&conf:ne=true';
                    break;
                case 2:
                    fetchUrl = 'isiWeb/web/v1/empresas/01/presuntos?conf:eq=true';
                    break;
            }
            try {
                const r = await fetch(url(fetchUrl), {
                    credentials: 'include',
                    method: 'GET',
                });

                if (!r.ok) {
                    throw new Error('Error loading presales');
                }

                const response = await r.json();
                this.presales = response.data as Presale[];
            } catch (error: any) {
                console.error(error);
            }
            this.loading = false;
        },

        async loadVendedores() {
            try {
                const r = await fetch(url('isiWeb/web/v1/empresas/01/vendedores'), {
                    credentials: 'include',
                    method: 'GET',
                });

                if (!r.ok) {
                    throw new Error('Error loading presale vendedor');
                }

                const response = await r.json();
                this.vendedores = response.data as Vendedor[];
            } catch (error: any) {
                console.error(error);
            }
        },
    }),
} as ComponentModule;
